#include <iostream>
#include <limits>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    for (int i = 0; i < n; i++) {
        int row_max = numeric_limits<int>::min();
        for (int j = 0; j < m; j++) {
            int x;
            cin >> x;
            if (x > row_max) row_max = x;
        }
        cout << row_max << '\n';
    }

    return 0;
}
